import fcntl
import os

class SharedFile:
    def __init__(self, filename, mode='r'):
        self.filename = filename
        self.mode = mode
        self.file = None

    def open_file(self):
        self.file = open(self.filename, self.mode)

    def acquire_shared_lock(self):
        fcntl.flock(self.file.fileno(), fcntl.LOCK_SH)

    def acquire_exclusive_lock(self):
        fcntl.flock(self.file.fileno(), fcntl.LOCK_EX)

    def release_lock(self):
        fcntl.flock(self.file.fileno(), fcntl.LOCK_UN)

    def close_file(self):
        if self.file:
            self.file.close()

# Usage example
def read_with_lock(filename):
    with SharedFile(filename, 'r') as f:
        f.open_file()
        f.acquire_shared_lock()
        data = f.file.read()
        f.release_lock()
        return data

def write_with_lock(filename, content):
    with SharedFile(filename, 'w') as f:
        f.open_file()
        f.acquire_exclusive_lock()
        f.file.write(content)
        f.release_lock()

#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>

struct flock create_lock(short type, short whence, off_t start, off_t len) {
    struct flock lock;
    lock.l_type = type;      // F_RDLCK or F_WRLCK
    lock.l_whence = whence;  // SEEK_SET, SEEK_CUR, SEEK_END
    lock.l_start = start;     // starting offset
    lock.l_len = len;        // 0 means entire file
    lock.l_pid = getpid();
    return lock;
}

int acquire_lock(int fd, struct flock *lock) {
    return fcntl(fd, F_SETLK, lock);
}

int acquire_blocking_lock(int fd, struct flock *lock) {
    return fcntl(fd, F_SETLKW, lock);
}

void release_lock(int fd, struct flock *lock) {
    lock->l_type = F_UNLCK;
    fcntl(fd, F_SETLK, lock);
}

// Example: Reader function
void read_file_shared(int fd) {
    struct flock lock = create_lock(F_RDLCK, SEEK_SET, 0, 0);
    acquire_blocking_lock(fd, &lock);

    // Read file contents here

    release_lock(fd, &lock);
}

// Example: Writer function
void write_file_exclusive(int fd) {
    struct flock lock = create_lock(F_WRLCK, SEEK_SET, 0, 0);
    acquire_blocking_lock(fd, &lock);

    // Write to file here

    release_lock(fd, &lock);
}
